#include <vector>
#include <map>
using namespace std;

long long solve(vector<vector<long long>> points) {
    const long long MOD = 1000000007;
    map<long long, int> y_counts;
    for (const auto& p : points) {
        y_counts[p[1]]++;
    }
    vector<int> counts;
    for (auto& [y, cnt] : y_counts) {
        counts.push_back(cnt);
    }
    long long total = 0;
    int n = counts.size();
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            long long c1 = counts[i];
            long long c2 = counts[j];
            long long comb1 = (c1 * (c1 - 1)) / 2;
            long long comb2 = (c2 * (c2 - 1)) / 2;
            total = (total + comb1 * comb2) % MOD;
        }
    }
    return total;
}
